class IapGateway {
  final InAppPurchase _iap = InAppPurchase.instance;
  StreamSubscription<List<PurchaseDetails>>? _sub;
  final _purchaseUpdates = StreamController<List<PurchaseDetails>>.broadcast();

  Stream<List<PurchaseDetails>> get purchaseUpdates => _purchaseUpdates.stream;

  Future<void> initialize() async {
    final available = await _iap.isAvailable();
    if (!available) throw PaymentException('iap_unavailable', 'In-app purchases unavailable');
    _sub ??= _iap.purchaseStream.listen((purchases) {
      _purchaseUpdates.add(purchases);
    }, onError: (e) {
      _purchaseUpdates.addError(e);
    });
  }

  Future<ProductDetails> getProduct(String productId) async {
    final resp = await _iap.queryProductDetails({productId});
    if (resp.error != null) {
      throw PaymentException('iap_query_failed', resp.error!.message);
    }
    final product = resp.productDetails.firstWhere(
      (p) => p.id == productId,
      orElse: () => throw PaymentException('iap_product_missing', 'Product not found: $productId'),
    );
    return product;
  }

  Future<void> buyConsumable(ProductDetails product, {String? applicationUserName}) async {
    final param = PurchaseParam(productDetails: product, applicationUserName: applicationUserName);
    final ok = await _iap.buyConsumable(purchaseParam: param);
    if (!ok) throw PaymentException('iap_start_failed', 'Failed to start purchase');
  }

  Future<void> buyNonConsumable(ProductDetails product, {String? applicationUserName}) async {
    final param = PurchaseParam(productDetails: product, applicationUserName: applicationUserName);
    final ok = await _iap.buyNonConsumable(purchaseParam: param);
    if (!ok) throw PaymentException('iap_start_failed', 'Failed to start purchase');
  }

  Future<void> complete(PurchaseDetails purchase) async {
    if (purchase.pendingCompletePurchase) {
      await _iap.completePurchase(purchase);
    }
  }

  Future<void> dispose() async {
    await _sub?.cancel();
    _sub = null;
    await _purchaseUpdates.close();
  }
}

class PaymentProcessor {
  final PaymentConfig config;
  final BackendClient backend;
  final WalletGateway wallet;
  final IapGateway iap;

  PaymentProcessor._(this.config, this.backend, this.wallet, this.iap);

  factory PaymentProcessor({
    required PaymentConfig config,
    BackendClient? backendClient,
    WalletGateway? walletGateway,
    IapGateway? iapGateway,
  }) {
    return PaymentProcessor._(
      config,
      backendClient ?? BackendClient(config),
      walletGateway ?? WalletGateway(),
      iapGateway ?? IapGateway(),
    );
  }

  Future<void> initialize() async {
    await iap.initialize();
  }

  Future<PaymentResult> purchaseIapAndFulfill({
    required String productId,
    required String userId,
    required bool consumable,
    String? applicationUserName,
  }) async {
    final product = await iap.getProduct(productId);

    final completer = Completer<PaymentResult>();
    StreamSubscription<List<PurchaseDetails>>? sub;

    sub = iap.purchaseUpdates.listen((purchases) async {
      try {
        for (final p in purchases) {
          if (p.productID != productId) continue;

          if (p.status == PurchaseStatus.pending) {
            continue;
          }

          if (p.status == PurchaseStatus.error) {
            await iap.complete(p);
            if (!completer.isCompleted) {
              completer.complete(PaymentResult.failure(
                errorCode: 'iap_error',
                errorMessage: p.error?.message ?? 'Purchase error',
              ));
            }
            continue;
          }

          if (p.status == PurchaseStatus.purchased || p.status == PurchaseStatus.restored) {
            final platform = Platform.isIOS ? 'ios' : (Platform.isAndroid ? 'android' : 'unknown');

            final payload = <String, dynamic>{
              'productId': p.productID,
              'purchaseId': p.purchaseID,
              'transactionDate': p.transactionDate,
              'status': describeEnum(p.status),
              'verificationData': {
                'localVerificationData': p.verificationData.localVerificationData,
                'serverVerificationData': p.verificationData.serverVerificationData,
                'source': describeEnum(p.verificationData.source),
              },
              'pendingCompletePurchase': p.pendingCompletePurchase,
            };

            final result = await backend.verifyAndFulfillIap(
              platform: platform,
              productId: productId,
              userId: userId,
              purchasePayload: payload,
            );

            await iap.complete(p);

            if (!completer.isCompleted) completer.complete(result);
            continue;
          }
        }
      } catch (e) {
        if (!completer.isCompleted) {
          completer.complete(PaymentResult.failure(
            errorCode: 'iap_fulfillment_failed',
            errorMessage: e.toString(),
          ));
        }
      }
    }, onError: (e) {
      if (!completer.isCompleted) {
        completer.complete(PaymentResult.failure(errorCode: 'iap_stream_error', errorMessage: e.toString()));
      }
    });

    try {
      if (consumable) {
        await iap.buyConsumable(product, applicationUserName: applicationUserName);
      } else {
        await iap.buyNonConsumable(product, applicationUserName: applicationUserName);
      }
    } catch (e) {
      await sub.cancel();
      return PaymentResult.failure(errorCode: 'iap_start_failed', errorMessage: e.toString());
    }

    final res = await completer.future.timeout(
      const Duration(minutes: 5),
      onTimeout: () => PaymentResult.failure(errorCode: 'iap_timeout', errorMessage: 'Purchase timed out'),
    );

    await sub.cancel();
    return res;
  }

  Future<PaymentResult> payWithWallet({
    required WalletType walletType,
    required int amountMinor,
    required String currency,
    required String country,
    required String merchantName,
    required String gatewayMerchantId,
    required String userId,
    Map<String, dynamic>? metadata,
    Map<String, dynamic>? lineItems,
  }) async {
    final available = await wallet.isAvailable(walletType);
    if (!available) {
      return PaymentResult.failure(
        errorCode: 'wallet_unavailable',
        errorMessage: 'Wallet not available on this device',
      );
    }

    final clientSecret = await backend.createWalletPaymentIntent(
      walletType: walletType,
      amountMinor: amountMinor,
      currency: currency,
      country: country,
      userId: userId,
      metadata: metadata,
    );

    final tokenPayload = await wallet.requestPaymentToken(
      type: walletType,
      amountMinor: amountMinor,
      currency: currency,
      country: country,
      merchantName: merchantName,
      gatewayMerchantId: gatewayMerchantId,
      lineItems: lineItems,
    );

    final result = await backend.confirmWalletPayment(
      walletType: walletType,
      clientSecret: clientSecret,
      walletTokenPayload: tokenPayload,
      userId: userId,
    );

    return result;
  }
}

class PaymentSecurity {
  PaymentSecurity._();

  static Map<String, String> pciSafeHeaders({
    required String publishableKey,
    String? idempotencyKey,
  }) {
    final headers = <String, String>{
      'X-Publishable-Key': publishableKey,
      'Cache-Control': 'no-store',
      'Pragma': 'no-cache',
    };
    if (idempotencyKey != null && idempotencyKey.isNotEmpty) {
      headers['Idempotency-Key'] = idempotencyKey;
    }
    return headers;
  }
}

